class Solution(object):
    def minDeletionSize(self, strs):
        n_cols = len(strs[0])
        deleted = 0
        for col in range(n_cols):
            for row in range(1, len(strs)):
                if strs[row][col] < strs[row-1][col]:
                    deleted += 1
                    break
        return deleted
